insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('700192b8-481e-4c15-9133-babddb44c022', 'foundation', 'teacher', 'bullying', 'bullying', 'When screens make you sad', 'Telling a grown up every time something on a screen feels bad.', 'Every child will see unkindness online. This strand makes sure they know what to do, whether it lands on them or someone else.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Telling a grown up every time something on a screen feels bad.', 'My child is 4 to 7. Help me with the lesson topic: When screens make you sad.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('a945e1c8-e6e7-42a9-b25f-cc3b1bd3aa87', 'foundation', 'teacher', 'identity', 'identity', 'Me on a screen and me in real life', 'Knowing the difference between a picture of a thing and the thing itself.', 'How children see themselves is shaped by what screens reflect back. This strand keeps the real self in charge of the online one.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Knowing the difference between a picture of a thing and the thing itself.', 'My child is 4 to 7. Help me with the lesson topic: Me on a screen and me in real life.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('55bc4e99-e52b-4a2e-8f0b-12a4adc5ff5b', 'foundation', 'teacher', 'information', 'information', 'Real or pretend?', 'Spotting the difference between stories, adverts and true things on a screen.', 'Feeds are built to hold attention, not to tell the truth. This strand teaches how information really reaches us and how to check it.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Spotting the difference between stories, adverts and true things on a screen.', 'My child is 4 to 7. Help me with the lesson topic: Real or pretend?.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('3d18ef91-7821-4a3d-baed-c33036d3a94b', 'foundation', 'teacher', 'ownership', 'ownership', 'Someone made that', 'Understanding that pictures, songs and games belong to the people who made them.', 'Everything online was made by someone. This strand teaches respect for other peoples work and pride in your own.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Understanding that pictures, songs and games belong to the people who made them.', 'My child is 4 to 7. Help me with the lesson topic: Someone made that.', 500, 'stub') on conflict do nothing;
