insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('d3063ba4-ae69-4322-9355-ec272b2fdb65', 'shaper', 'teacher', 'information', 'information', 'Deepfakes and doctored truth', 'Verifying before believing or sharing, because seeing is no longer proof.', 'Feeds are built to hold attention, not to tell the truth. This strand teaches how information really reaches us and how to check it.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Verifying before believing or sharing, because seeing is no longer proof.', 'My child is 13 to 15. Help me with the lesson topic: Deepfakes and doctored truth.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('e8ce7de5-daec-4d40-a104-5c9acff23ad0', 'shaper', 'teacher', 'ownership', 'ownership', 'Your work has value', 'Protecting what you make and post, because it is worth something.', 'Everything online was made by someone. This strand teaches respect for other peoples work and pride in your own.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Protecting what you make and post, because it is worth something.', 'My child is 13 to 15. Help me with the lesson topic: Your work has value.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('01d8fdcb-5eda-4603-9857-1309cdad8187', 'shaper', 'teacher', 'privacy', 'privacy', 'Scams aimed at teenagers', 'Recognising sextortion, fake offers and pressure tactics, and what to do next.', 'Personal information is valuable and children give it away without knowing. This strand builds the privacy shield early and keeps it growing.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Recognising sextortion, fake offers and pressure tactics, and what to do next.', 'My child is 13 to 15. Help me with the lesson topic: Scams aimed at teenagers.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('daa67813-7e3b-46d6-a5dc-a37daf380217', 'shaper', 'teacher', 'relationships', 'relationships', 'Relationships, pressure and phones', 'Recognising pressure in private messages and knowing consent applies online.', 'Connection is the strongest protective factor in all the research. This strand teaches warmth, boundaries and judgement with people through screens.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Recognising pressure in private messages and knowing consent applies online.', 'My child is 13 to 15. Help me with the lesson topic: Relationships, pressure and phones.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('796f2e0c-fd6d-445d-85e2-098216a6fd5b', 'shaper', 'teacher', 'reputation', 'reputation', 'Reputation and the long game', 'Reading your own posts the way a sixth form, a coach or an employer will.', 'What goes online stays reachable. This strand builds the habit of thinking in years, not minutes.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Reading your own posts the way a sixth form, a coach or an employer will.', 'My child is 13 to 15. Help me with the lesson topic: Reputation and the long game.', 500, 'stub') on conflict do nothing;
insert into public.lessons (id, stage_id, audience, strand, category, title, the_idea, why_it_matters, try_this, key_message, digi_prompt, sort_order, status) values ('2e445c09-f7e6-43e3-8b4c-e2915ebae126', 'shaper', 'teacher', 'wellbeing', 'wellbeing', 'Sleep is not optional', 'Keeping nine hours a night when the phone wants them all.', 'Sleep, mood and movement are where screens bite first. This strand builds routines that protect all three without a daily fight.', 'The full lesson with its video is on the way. Ask DiGi to walk you through this topic today.', 'Keeping nine hours a night when the phone wants them all.', 'My child is 13 to 15. Help me with the lesson topic: Sleep is not optional.', 500, 'stub') on conflict do nothing;
